import { useEffect } from "react";
export const useHotkey = ({ ref, key, callback }) => {
    useEffect(() => {
        const element = ref.current;
        if (!element)
            return;
        const handler = (e) => {
            if (e.key === key) {
                e.preventDefault();
                callback(e);
            }
        };
        element.addEventListener("keydown", handler);
        return () => element.removeEventListener("keydown", handler);
    }, [key, callback, ref]);
};
